    26→      return false;
    27→    }
    28→  }
    29→
    30→  /**
    31→   * Start analyzing video stream
    32→   * @param {HTMLVideoElement} videoElement
    33→   * @param {number} sampleRate - Analyze every N milliseconds (default: 500ms)
    34→   */
    35→  startAnalysis(videoElement, sampleRate = 500) {
    36→    if (!this.model) {
    37→      console.error('Model not initialized. Call init() first.');
    38→      return;
    39→    }
    40→
    41→    this.isAnalyzing = true;
    42→    this.startTime = Date.now();
    43→    this.frameData = [];
    44→
    45→    const analyze = async () => {
    46→      if (!this.isAnalyzing) return;
    47→
    48→      try {
    49→        const timestamp = Date.now() - this.startTime;
    50→        const frame = await this.analyzeFrame(videoElement, timestamp);
    51→
    52→        if (frame) {
    53→          this.frameData.push(frame);
    54→          this.emit('frame', frame);
    55→
    56→          // Calculate live scores every 5 seconds
    57→          if (this.frameData.length % 10 === 0) {
    58→            const scores = this.calculateLiveScores();
    59→            this.emit('scores', scores);
    60→          }
    61→        }
    62→      } catch (err) {
    63→        console.error('Frame analysis error:', err);
    64→      }
    65→
    66→      setTimeout(analyze, sampleRate);
    67→    };
    68→
    69→    analyze();
    70→  }
    71→
    72→  /**
    73→   * Stop analyzing
    74→   */
    75→  stopAnalysis() {
    76→    this.isAnalyzing = false;
    77→  }
    78→
    79→  /**
    80→   * Analyze a single frame
    81→   */
    82→  async analyzeFrame(videoElement, timestamp) {
    83→    try {
    84→      const predictions = await this.model.estimateFaces(videoElement, false);
    85→
    86→      if (predictions.length === 0) {
    87→        return {
    88→          timestamp,
    89→          faceDetected: false,
    90→          eyeContact: 0,
    91→          headPose: 'unknown',
    92→          confidence: 0
    93→        };
    94→      }
    95→
    96→      const face = predictions[0];
    97→
    98→      // Calculate eye contact (center focus)
    99→      const eyeContact = this.calculateEyeContact(face, videoElement);
   100→
   101→      // Estimate head pose
   102→      const headPose = this.estimateHeadPose(face, videoElement);
   103→
   104→      // Detect micro-expressions (simplified)
   105→      const expression = this.detectExpression(face);
   106→
   107→      return {
   108→        timestamp,
   109→        faceDetected: true,
   110→        eyeContact,
   111→        headPose,
   112→        expression,
   113→        confidence: face.probability[0],
   114→        boundingBox: face.topLeft
   115→      };
   116→    } catch (err) {
   117→      console.error('Frame analysis error:', err);
   118→      return null;
   119→    }
   120→  }
   121→
   122→  /**
   123→   * Calculate eye contact score (0-100)
   124→   * Higher when face is centered and looking forward
   125→   */
   126→  calculateEyeContact(face, videoElement) {
   127→    const [x, y] = face.topLeft;
   128→    const [width, height] = [face.bottomRight[0] - face.topLeft[0], face.bottomRight[1] - face.topLeft[1]];
   129→
   130→    const centerX = x + width / 2;
   131→    const centerY = y + height / 2;
   132→
   133→    const videoCenterX = videoElement.videoWidth / 2;
   134→    const videoCenterY = videoElement.videoHeight / 2;
   135→
   136→    // Distance from center (normalized)
   137→    const distX = Math.abs(centerX - videoCenterX) / (videoElement.videoWidth / 2);
   138→    const distY = Math.abs(centerY - videoCenterY) / (videoElement.videoHeight / 2);
   139→
   140→    const distance = Math.sqrt(distX * distX + distY * distY);
   141→
   142→    // Score: 100 when centered, decreases with distance
   143→    const score = Math.max(0, Math.min(100, 100 - (distance * 50)));
   144→
   145→    return Math.round(score);
   146→  }
   147→
   148→  /**
   149→   * Estimate head pose (simplified)
   150→   */
   151→  estimateHeadPose(face, videoElement) {
   152→    const [x, y] = face.topLeft;
   153→    const [width, height] = [face.bottomRight[0] - face.topLeft[0], face.bottomRight[1] - face.topLeft[1]];
   154→
   155→    const centerX = x + width / 2;
   156→    const videoCenterX = videoElement.videoWidth / 2;
   157→
   158→    const xOffset = (centerX - videoCenterX) / (videoElement.videoWidth / 2);
   159→
   160→    if (xOffset < -0.3) return 'left';
   161→    if (xOffset > 0.3) return 'right';
   162→    if (height / width < 1.2) return 'down';
   163→    if (height / width > 1.5) return 'up';
   164→    return 'forward';
   165→  }
   166→
   167→  /**
   168→   * Detect expression (simplified - would need dedicated model for accuracy)
   169→   */
   170→  detectExpression(face) {
   171→    // This is a placeholder - real expression detection needs FaceMesh or similar
   172→    // For now, use confidence and face size as proxy
   173→    const confidence = face.probability[0];
   174→
   175→    if (confidence > 0.95) return 'confident';
   176→    if (confidence > 0.85) return 'neutral';
   177→    if (confidence < 0.7) return 'nervous';
   178→    return 'neutral';
   179→  }
   180→
   181→  /**
   182→   * Calculate live scores from collected frames
   183→   */
   184→  calculateLiveScores() {
   185→    if (this.frameData.length === 0) {
   186→      return {
   187→        eyeContact: 0,
   188→        headStability: 0,
   189→        presence: 0
   190→      };
   191→    }
   192→
   193→    const recentFrames = this.frameData.slice(-20); // Last 20 frames (~10 seconds)
   194→
   195→    // Eye contact: average of scores where face was detected
   196→    const eyeContactFrames = recentFrames.filter(f => f.faceDetected);
   197→    const eyeContact = eyeContactFrames.length > 0
   198→      ? eyeContactFrames.reduce((sum, f) => sum + f.eyeContact, 0) / eyeContactFrames.length
   199→      : 0;
   200→
   201→    // Head stability: consistency of head pose
   202→    const forwardFrames = recentFrames.filter(f => f.headPose === 'forward').length;
   203→    const headStability = (forwardFrames / recentFrames.length) * 100;
   204→
   205→    // Presence: how often face is detected
   206→    const presence = (eyeContactFrames.length / recentFrames.length) * 100;
   207→
   208→    return {
   209→      eyeContact: Math.round(eyeContact),
   210→      headStability: Math.round(headStability),
   211→      presence: Math.round(presence)
   212→    };
   213→  }
   214→
   215→  /**
   216→   * Get final analysis summary
   217→   */
   218→  getFinalAnalysis() {
   219→    if (this.frameData.length === 0) {
   220→      return null;
   221→    }
   222→
   223→    const totalDuration = (Date.now() - this.startTime) / 1000; // seconds
   224→
   225→    // Calculate overall metrics
   226→    const framesWithFace = this.frameData.filter(f => f.faceDetected);
   227→    const presencePercent = (framesWithFace.length / this.frameData.length) * 100;
   228→
   229→    const avgEyeContact = framesWithFace.length > 0
   230→      ? framesWithFace.reduce((sum, f) => sum + f.eyeContact, 0) / framesWithFace.length
   231→      : 0;
   232→
   233→    // Head pose distribution
   234→    const poseCount = {
   235→      forward: 0,
   236→      left: 0,
   237→      right: 0,
   238→      up: 0,
   239→      down: 0,
   240→      unknown: 0
   241→    };
   242→
   243→    framesWithFace.forEach(f => {
   244→      poseCount[f.headPose]++;
   245→    });
   246→
   247→    // Expression distribution
   248→    const expressionCount = {
   249→      confident: 0,
   250→      neutral: 0,
   251→      nervous: 0
   252→    };
   253→
   254→    framesWithFace.forEach(f => {
   255→      expressionCount[f.expression]++;
   256→    });
   257→
   258→    // Calculate scores (0-100)
   259→    const eyeContactScore = avgEyeContact;
   260→    const bodyLanguageScore = (poseCount.forward / framesWithFace.length) * 100;
   261→    const expressionScore = ((expressionCount.confident * 1.0 + expressionCount.neutral * 0.7 + expressionCount.nervous * 0.3) / framesWithFace.length) * 100;
   262→    const presenceScore = presencePercent;
   263→
   264→    // Overall presentation score
   265→    const presentationScore = (
   266→      eyeContactScore * 0.35 +
   267→      bodyLanguageScore * 0.25 +
   268→      expressionScore * 0.25 +
   269→      presenceScore * 0.15
   270→    );
   271→
   272→    return {
   273→      duration: totalDuration,
   274→      totalFrames: this.frameData.length,
   275→      framesAnalyzed: framesWithFace.length,
   276→      scores: {
   277→        eyeContact: Math.round(eyeContactScore),
   278→        bodyLanguage: Math.round(bodyLanguageScore),
   279→        expression: Math.round(expressionScore),
   280→        presence: Math.round(presenceScore),
   281→        presentation: Math.round(presentationScore)
   282→      },
   283→      insights: {
   284→        poseDistribution: poseCount,
   285→        expressionDistribution: expressionCount,
   286→        avgConfidence: framesWithFace.reduce((sum, f) => sum + (f.confidence || 0), 0) / framesWithFace.length
   287→      },
   288→      frameData: this.frameData // Include for detailed timeline
   289→    };
   290→  }
   291→
   292→  /**
   293→   * Event listener system
   294→   */
   295→  on(event, callback) {
   296→    if (!this.listeners[event]) {
   297→      this.listeners[event] = [];
   298→    }
   299→    this.listeners[event].push(callback);
