   166→      console.log('Microphone active:', track.label);
   167→    } else {
   168→      console.warn('No microphone detected in stream');
   169→    }
   170→  } catch (err) {
   171→    console.warn('Camera/microphone not available:', err);
   172→  }
   173→}
   174→
   175→// Submit response
   176→async function submitResponse() {
   177→  const responseText = document.getElementById('response-text').value.trim();
   178→  
   179→  if (!responseText) {
   180→    alert('Please provide a response before submitting.');
   181→    return;
   182→  }
   183→  
   184→  showLoading('Analyzing your response...');
   185→  
   186→  try {
   187→    const data = await apiCall(`/interviews/${interviewState.interviewId}/respond`, {
   188→      method: 'POST',
   189→      body: JSON.stringify({
   190→        question_index: interviewState.currentQuestionIndex,
   191→        response_text: responseText
   192→      })
   193→    });
   194→    
   195→    if (!data || !data.success) {
   196→      throw new Error(data?.error || 'Failed to submit response');
   197→    }
   198→    
   199→    interviewState.responses[interviewState.currentQuestionIndex] = {
   200→      text: responseText,
   201→      analysis: data.analysis
   202→    };
   203→    
   204→    hideLoading();
   205→    showFeedback(data.analysis);
   206→    
   207→  } catch (err) {
   208→    hideLoading();
   209→    alert('Failed to analyze response: ' + err.message);
   210→  }
   211→}
   212→
   213→// Show feedback for response
   214→function showFeedback(analysis) {
   215→  document.getElementById('interview-screen').style.display = 'none';
   216→  document.getElementById('feedback-screen').style.display = 'flex';
   217→  
   218→  document.getElementById('question-score').textContent = `${analysis.score}/10`;
   219→  
   220→  const strengthsList = document.getElementById('feedback-strengths');
   221→  strengthsList.innerHTML = (analysis.strengths || []).map(s => `<li>${s}</li>`).join('');
   222→  
   223→  const improvementsList = document.getElementById('feedback-improvements');
   224→  improvementsList.innerHTML = (analysis.improvements || []).map(i => `<li>${i}</li>`).join('');
   225→  
   226→  document.getElementById('feedback-detailed').textContent = analysis.detailed_feedback || '';
   227→  
   228→  // Setup next button
   229→  document.getElementById('next-question-btn').onclick = () => {
   230→    interviewState.currentQuestionIndex++;
   231→    document.getElementById('feedback-screen').style.display = 'none';
   232→    document.getElementById('interview-screen').style.display = 'flex';
   233→    displayQuestion(interviewState.currentQuestionIndex);
   234→  };
   235→  
   236→  // Update button text for last question
   237→  if (interviewState.currentQuestionIndex >= interviewState.questions.length - 1) {
   238→    document.getElementById('next-question-btn').innerHTML = 'See Results <span>→</span>';
   239→  }
   240→}
   241→
   242→// Skip question
   243→function skipQuestion() {
   244→  interviewState.currentQuestionIndex++;
   245→  displayQuestion(interviewState.currentQuestionIndex);
   246→}
   247→
   248→// Complete interview
   249→async function completeInterview() {
   250→  showLoading('Generating your final results...');
   251→  
   252→  try {
   253→    const data = await apiCall(`/interviews/${interviewState.interviewId}/complete`, {
   254→      method: 'POST'
   255→    });
   256→    
   257→    if (!data || !data.success) {
   258→      throw new Error(data?.error || 'Failed to complete interview');
   259→    }
   260→    
   261→    hideLoading();
   262→    displayResults(data);
   263→    
   264→  } catch (err) {
