   271→// Display final results
   272→function displayResults(data) {
   273→  const feedback = data.overall_feedback || data.ai_feedback || {};
   274→  
   275→  document.getElementById('setup-screen').style.display = 'none';
   276→  document.getElementById('interview-screen').style.display = 'none';
   277→  document.getElementById('feedback-screen').style.display = 'none';
   278→  document.getElementById('progress-container').style.display = 'none';
   279→  document.getElementById('results-screen').style.display = 'flex';
   280→  
   281→  document.getElementById('overall-score').textContent = feedback.overall_score || '-';
   282→  document.getElementById('overall-summary').textContent = feedback.summary || 'Interview completed.';
   283→  
   284→  // Set readiness badge
   285→  const badge = document.getElementById('readiness-badge');
   286→  const readiness = feedback.interview_readiness || 'almost_ready';
   287→  badge.textContent = readiness === 'ready' ? 'Interview Ready!' : 
   288→                       readiness === 'almost_ready' ? 'Almost Ready' : 'Needs Practice';
   289→  badge.className = 'readiness-badge ' + 
   290→    (readiness === 'ready' ? 'ready' : readiness === 'almost_ready' ? 'almost' : 'needs-work');
   291→  
   292→  // Strengths
   293→  const strengthsList = document.getElementById('results-strengths');
   294→  strengthsList.innerHTML = (feedback.top_strengths || []).map(s => `<li>${s}</li>`).join('') || '<li>Complete more questions for detailed feedback</li>';
   295→  
   296→  // Improvements
   297→  const improvementsList = document.getElementById('results-improvements');
   298→  improvementsList.innerHTML = (feedback.priority_improvements || []).map(i => `<li>${i}</li>`).join('') || '<li>Complete more questions for detailed feedback</li>';
   299→  
   300→  // Recommendations
   301→  const recommendationsList = document.getElementById('results-recommendations');
   302→  recommendationsList.innerHTML = (feedback.recommended_practice || []).map(r => `<li>${r}</li>`).join('') || '<li>Keep practicing to improve your interview skills</li>';
   303→}
